fun downloadModel() {
    if (_uiState.value.downloading) return

    _uiState.update { it.copy(downloading = true, downloadProgress = 0, downloadMessage = "准备下载...") }

    viewModelScope.launch(Dispatchers.IO) {
        val result = modelManager.downloadModel { downloaded, total, percent, fileName ->
            _uiState.update {
                it.copy(
                    downloadProgress = percent,
                    downloadMessage = "下载中: $fileName (${downloaded / 1024 / 1024}MB / ${total / 1024 / 1024}MB)"
                )
            }
        }

        if (result.isSuccess) {
            _uiState.update {
                it.copy(
                    downloading = false,
                    downloadProgress = 100,
                    downloadMessage = "下载完成",
