            }
            kotlinx.coroutines.delay(2000)
            _uiState.update { it.copy(downloadMessage = "") }
        } else {
            _uiState.update {
                it.copy(
                    downloading = false,
                    downloadProgress = 0,
                    downloadMessage = "下载失败: ${result.exceptionOrNull()?.message}"
                )
            }
        }
    }
}

