    val transcribeTesting: Boolean = false,
    // 模型下载
    val modelDownloaded: Boolean = false,
    val modelSizeMB: Double = 0.0,
    val modelPath: String = "",
    val downloading: Boolean = false,
    val downloadProgress: Int = 0,
    val downloadMessage: String = ""
)

@HiltViewModel
class AISettingsViewModel @Inject constructor(
    private val configStore: AIConfigStore,
    private val aiService: AIService,
    private val whisperService: com.multilanglearner.data.network.WhisperService,
    private val modelManager: ModelManager
) : ViewModel() {
    private val _uiState = MutableStateFlow(AISettingsUiState())
    val uiState: StateFlow<AISettingsUiState> = _uiState.asStateFlow()

    init {
        viewModelScope.launch {
            configStore.config.first().let { cfg ->
                _uiState.update {
                    it.copy(
                        provider = cfg.provider, apiKey = cfg.apiKey,
                        baseUrl = cfg.baseUrl, model = cfg.model,
                        maxTokens = cfg.maxTokens?.toString() ?: "",
                        temperature = cfg.temperature?.toString() ?: "",
                        groqWhisperEnabled = cfg.groqWhisperEnabled,
                        whisperModel = cfg.whisperModel,
                        subtitleTranslateMode = cfg.subtitleTranslateMode,
                        groqApiKey = cfg.groqApiKey,
                        transcribeLanguage = cfg.transcribeLanguage,
                        transcriptionMode = cfg.transcriptionMode,
                        modelDownloaded = modelManager.isModelDownloaded(),
                        modelSizeMB = modelManager.getModelSizeMB(),
                        modelPath = modelManager.getModelPath() ?: modelManager.getDefaultModelPath()
                    )
                }
            }
        }
    }

    fun setProvider(p: String) { _uiState.update { it.copy(provider = p) } }
    fun setApiKey(k: String) { _uiState.update { it.copy(apiKey = k) } }
    fun setBaseUrl(u: String) { _uiState.update { it.copy(baseUrl = u) } }
    fun setModel(m: String) { _uiState.update { it.copy(model = m) } }
    fun setMaxTokens(t: String) { _uiState.update { it.copy(maxTokens = t) } }
    fun setTemperature(t: String) { _uiState.update { it.copy(temperature = t) } }
    fun setGroqWhisper(e: Boolean) { _uiState.update { it.copy(groqWhisperEnabled = e) } }
    fun setWhisperModel(m: String) { _uiState.update { it.copy(whisperModel = m) } }
    fun setTranslateMode(m: String) { _uiState.update { it.copy(subtitleTranslateMode = m) } }
    fun setGroqApiKey(k: String) { _uiState.update { it.copy(groqApiKey = k) } }
    fun setTranscribeLanguage(l: String) { _uiState.update { it.copy(transcribeLanguage = l) } }

    // 转录模式切换时立即保存，提升流畅度
    fun setTranscriptionMode(m: String) {
        _uiState.update { it.copy(transcriptionMode = m) }
        viewModelScope.launch {
            val state = _uiState.value
            configStore.save(AIConfig(
                provider = state.provider, apiKey = state.apiKey,
                baseUrl = state.baseUrl, model = state.model,
                maxTokens = state.maxTokens.toIntOrNull(),
                temperature = state.temperature.toDoubleOrNull(),
                groqWhisperEnabled = state.groqWhisperEnabled,
                whisperModel = state.whisperModel,
                subtitleTranslateMode = state.subtitleTranslateMode,
                groqApiKey = state.groqApiKey,
                transcribeLanguage = state.transcribeLanguage,
                transcriptionMode = m  // 使用新的转录模式
            ))
        }
    }

    fun save() {
        viewModelScope.launch {
            val state = _uiState.value
            configStore.save(AIConfig(
                provider = state.provider, apiKey = state.apiKey,
                baseUrl = state.baseUrl, model = state.model,
                maxTokens = state.maxTokens.toIntOrNull(),
                temperature = state.temperature.toDoubleOrNull(),
                groqWhisperEnabled = state.groqWhisperEnabled,
                whisperModel = state.whisperModel,
                subtitleTranslateMode = state.subtitleTranslateMode,
                groqApiKey = state.groqApiKey,
                transcribeLanguage = state.transcribeLanguage,
                transcriptionMode = state.transcriptionMode
            ))
            // Show save success feedback
            _uiState.update { it.copy(saveSuccess = true) }
            kotlinx.coroutines.delay(1500)
            _uiState.update { it.copy(saveSuccess = false) }
        }
    }

    fun testConnection() {
        _uiState.update { it.copy(testResult = "测试中...", testSuccess = false) }
        viewModelScope.launch(Dispatchers.IO) {
            val state = _uiState.value
            val config = AIConfig(
                provider = state.provider, apiKey = state.apiKey,
                baseUrl = state.baseUrl, model = state.model,
                maxTokens = state.maxTokens.toIntOrNull(),
                temperature = state.temperature.toDoubleOrNull()
            )
            val result = aiService.chat(config, "请回复\"连接成功\"四个字")
            _uiState.update {
                if (result != null) it.copy(testResult = "✅ $result", testSuccess = true)
                else it.copy(testResult = "❌ 连接失败，请检查设置", testSuccess = false)
            }
        }
    }

    /**
     * 测试转录引擎连接
     * 通过发送一个简单的 API 请求来验证 Groq API Key 是否有效
     */
    fun testTranscribeConnection() {
        _uiState.update { it.copy(transcribeTestResult = "测试中...", transcribeTestSuccess = false, transcribeTesting = true) }
        viewModelScope.launch(Dispatchers.IO) {
            val state = _uiState.value
            val groqKey = state.groqApiKey.ifBlank {
                // 如果没有专门的 Groq Key，检查是否使用 Groq 作为 AI provider
                if (state.provider == "groq") state.apiKey else ""
            }

            if (groqKey.isBlank()) {
                _uiState.update { it.copy(
                    transcribeTestResult = "❌ 请先输入 Groq API Key",
                    transcribeTestSuccess = false,
                    transcribeTesting = false
                )}
                return@launch
            }

            // 使用 AIService 测试连接
            val config = AIConfig(
                provider = "groq",
                apiKey = groqKey,
                baseUrl = "",
                model = state.whisperModel
            )

            // 发送简单测试请求
            val testResult = aiService.chat(config, "Hi")

            if (testResult != null) {
                _uiState.update { it.copy(
                    transcribeTestResult = "✅ Groq API 连接成功",
                    transcribeTestSuccess = true,
                    transcribeTesting = false
                )}
            } else {
                _uiState.update { it.copy(
                    transcribeTestResult = "❌ 连接失败，请检查 API Key",
                    transcribeTestSuccess = false,
                    transcribeTesting = false
                )}
            }
        }
    }
}

